In C++, you can start a new process and connect one file descriptor to its input and output using the `fork()` and `exec()` family of functions. You can also use the `dup2()` function to redirect file descriptors. Here's a step-by-step example:

1. **Fork the Process**: Create a new process using `fork()`.
2. **Close Unnecessary Descriptors**: Close any descriptors that are not needed.
3. **Redirect File Descriptors**: Use `dup2()` to redirect file descriptors.
4. **Execute the New Program**: Use `exec()` to run the new program.

Here's an example that demonstrates this:

```cpp
#include <iostream>
#include <unistd.h>
#include <sys/types.h>
#include <sys/wait.h>
#include <fcntl.h>
#include <stdio.h>

int main() {
    int pipefd[2];
    pid_t pid;

    // Create a pipe
    if (pipe(pipefd) == -1) {
        perror("pipe");
        return 1;
    }

    // Fork a new process
    pid = fork();
    if (pid == -1) {
        perror("fork");
        return 1;
    }

    // Parent process
    if (pid > 0) {
        // Close the write end of the pipe in the parent
        close(pipefd[1]);

        // Wait for the child process to finish
        wait(NULL);

        // Read from the pipe
        char buffer[100];
        ssize_t bytes_read = read(pipefd[0], buffer, sizeof(buffer));
        if (bytes_read > 0) {
            buffer[bytes_read] = '\0';
            std::cout << "Parent received: " << buffer << std::endl;
        }

        // Close the read end of the pipe
        close(pipefd[0]);
        return 0;
    } 

    // Child process
    if (pid == 0) {
        // Close the read end of the pipe
        close(pipefd[0]);

        // Redirect stdin and stdout to the pipe
        dup2(pipefd[1], STDIN_FILENO);
        dup2(pipefd[1], STDOUT_FILENO);

        // Close the write end of the pipe
        close(pipefd[1]);

        // Execute the new program
        execlp("cat", "cat", NULL);
        perror("execlp");
        _exit(1);
    }

    return 0;
}
``

